 1	import React, { useState } from 'react';
 2	
 3	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Card, CardBody, CardHeader, CardTitle, SelectOption } from '@patternfly/react-core';
 6	
 7	import { vmsPerResourceOptions } from './utils/constants';
 8	import VMsPerResourceChart from './VMsPerResourceChart';
 9	
10	import './VMsPerResourceCard.scss';
11	
12	const VMsPerResourceCard = () => {
13	  const { t } = useKubevirtTranslation();
14	  const [vmResourceOption, setvmResourceOption] = useState(vmsPerResourceOptions[0]?.title);
15	  const [type, setType] = useState(vmsPerResourceOptions[0]?.type);
16	
17	  const handleSelect = (event, value) => {
18	    const selected = vmsPerResourceOptions?.find((option) => option.title === value);
19	    setvmResourceOption(selected?.title);
20	    setType(selected?.type);
21	  };
22	
23	  return (
24	    <Card className="vms-per-resource-card__gradient" data-test-id="vms-per-template-card">
25	      <CardHeader
26	        actions={{
27	          actions: (
28	            <FormPFSelect
29	              onSelect={handleSelect}
30	              selected={vmResourceOption}
31	              toggleProps={{ id: 'overview-vms-per-resource-card' }}
32	            >
33	              {vmsPerResourceOptions?.map((scope) => (
34	                <SelectOption key={scope.type} value={scope.title}>
35	                  {scope.title}
36	                </SelectOption>
37	              ))}
38	            </FormPFSelect>
39	          ),
40	        }}
41	      >
42	        <CardTitle>{t('VirtualMachines per resource')}</CardTitle>
43	      </CardHeader>
44	      <CardBody>
45	        <VMsPerResourceChart type={type} />
46	      </CardBody>
47	    </Card>
48	  );
49	};
50	
51	export default VMsPerResourceCard;

